#include<bits/stdc++.h>
using namespace std;
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ; 
}
typedef long long ll;
const int N=5010;int n,w[N],siz[N];vector<int> G[N];
ll dp[N][N],ans=0x3f3f3f3f3f3f3f3fll,g[N];
inline void dfs(int u,int f=0)
{
//	printf("dfs %d\n",u);
	siz[u]=1;dp[u][1]=0;
	for(int v:G[u])if(v!=f)
	{
		dfs(v,u);
		memcpy(g+1,dp[u]+1,siz[u]*sizeof(ll));
		memset(dp[u]+1,0x3f,siz[u]*sizeof(ll));
		drep(siz[u],1,i)
		{
			drep(siz[v],1,j)
			{
				dp[u][i+j]=min(dp[u][i+j],g[i]+dp[v][j]);
				dp[u][i+1]=min(dp[u][i+1],g[i]+dp[v][j]+w[j]);
			}
		}
		siz[u]+=siz[v];
	}
//	printf("%d :: ",u);rep(1,n,i)printf("%lld ",dp[u][i]>1000?-1:dp[u][i]);puts("");
}
int main()
{
	n=read();rep(2,n,i)w[i]=read();
	rep(2,n,i)
	{
		int x=read(),y=read();
		G[x].push_back(y);G[y].push_back(x);
	}
	memset(dp,0x3f,sizeof(dp));dfs(1);
	rep(1,n,i)ans=min(ans,dp[1][i]+w[i]);printf("%lld\n",ans);
}
